outbound.set-body:
@{
            var random = new Random(context.RequestId.GetHashCode());
            var promptTokens = random.Next(10, 200);
            var completionTokens = random.Next(50, 500);
            var totalTokens = promptTokens + completionTokens;
            return new Newtonsoft.Json.Linq.JObject(
                new Newtonsoft.Json.Linq.JProperty("id", "chatcmpl-" + context.RequestId.ToString("N").Substring(0, 12)),
                new Newtonsoft.Json.Linq.JProperty("object", "chat.completion"),
                new Newtonsoft.Json.Linq.JProperty("model", "gpt-4o"),
                new Newtonsoft.Json.Linq.JProperty("usage", new Newtonsoft.Json.Linq.JObject(
                    new Newtonsoft.Json.Linq.JProperty("prompt_tokens", promptTokens),
                    new Newtonsoft.Json.Linq.JProperty("completion_tokens", completionTokens),
                    new Newtonsoft.Json.Linq.JProperty("total_tokens", totalTokens)
                )),
                new Newtonsoft.Json.Linq.JProperty("choices", new Newtonsoft.Json.Linq.JArray(
                    new Newtonsoft.Json.Linq.JObject(
                        new Newtonsoft.Json.Linq.JProperty("message", new Newtonsoft.Json.Linq.JObject(
                            new Newtonsoft.Json.Linq.JProperty("role", "assistant"),
                            new Newtonsoft.Json.Linq.JProperty("content", "Mock response for cost tracking demonstration.")
                        )),
                        new Newtonsoft.Json.Linq.JProperty("finish_reason", "stop"),
                        new Newtonsoft.Json.Linq.JProperty("index", 0)
                    )
                ))
            ).ToString();
        }
